components.css:
.ds-btn-primary { 
  display: inline-flex;
  shrink: 0;
  align-items: center;
  justify-content: center;
  border-radius: 0.75rem; /* rounded-lg */
  border: 1px solid transparent;
  background-color: #6B7C47; /* bg-primary */
  color: #FDFAF5; /* text-primary-foreground */
  padding: 0.625rem 1rem; /* px-2.5, h-8 -> roughly */
  font-size: 0.875rem; /* text-sm */
  font-weight: 500;
  white-space: nowrap;
  transition: all 0.2s ease-in-out;
  outline: none;
  user-select: none;
}
.ds-btn-primary:hover { 
  background-color: rgba(107, 124, 71, 0.8); /* hover:bg-primary/80 */
}
.ds-btn-primary:focus-visible {
  border-color: #6B7C47; /* focus-visible:border-ring */
  box-shadow: 0 0 0 3px rgba(107, 124, 71, 0.5); /* focus-visible:ring-3 focus-visible:ring-ring/50 */
}
.ds-btn-primary:active {
  transform: translateY(1px); /* active:not-aria-[haspopup]:translate-y-px */
}
.ds-btn-primary:disabled {
  pointer-events: none;
  opacity: 0.5;
}
.ds-btn-primary[aria-invalid='true'] {
  border-color: #9E4A5C; /* aria-invalid:border-destructive */
  box-shadow: 0 0 0 3px rgba(158, 74, 92, 0.2); /* aria-invalid:ring-3 aria-invalid:ring-destructive/20 */
}

.ds-magnetic-btn {
  position: relative;
  padding: 1.25rem 2.5rem; /* px-10 py-5 */
  border-radius: 9999px; /* rounded-full */
  background-color: #6B7C47; /* bg-primary */
  color: #2C1810; /* text-text-deep */
  overflow: hidden;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  /* Framer motion styles are JS-driven, not pure CSS */
}
.ds-magnetic-btn-bg {
  position: absolute;
  inset: 0;
  background-color: #6B2737; /* bg-accent */
  transform: translateY(100%);
  transition: transform 500ms ease-out;
}
.ds-magnetic-btn:hover .ds-magnetic-btn-bg {
  transform: translateY(0%);
}
.ds-magnetic-btn-text {
  position: relative;
  z-index: 10;
  font-family: 'Lato', ui-sans-serif, system-ui, sans-serif; /* font-sans */
  font-weight: 900; /* font-black */
  letter-spacing: 0.1em; /* tracking-widest */
  text-transform: uppercase;
  font-size: 0.625rem; /* text-[10px] */
  display: flex;
  align-items: center;
  gap: 0.5rem;
}
.ds-magnetic-btn-text svg {
  width: 0.75rem;
  height: 0.75rem; /* size-3 */
  flex-shrink: 0;
}
